# Requires: pip install debugpy anthropic
import asyncio
import debugpy

# Start debug server — connect VS Code with 'Python: Attach' on port 5678
debugpy.listen(5678)
print("Waiting for VS Code debugger to attach...")
debugpy.wait_for_client()

import anthropic
import json

client = anthropic.Anthropic()

TOOLS = [
    {
        "name": "get_weather",
        "description": "Return current weather for a city.",
        "input_schema": {
            "type": "object",
            "properties": {
                "city": {"type": "string"},
                "units": {"type": "string", "enum": ["celsius", "fahrenheit"]},
            },
            "required": ["city"],
        },
    }
]

async def run_agent(user_message: str):
    messages = [{"role": "user", "content": user_message}]

    for step in range(5):
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            tools=TOOLS,
            messages=messages,
        )

        # Breakpoint fires before tool dispatch — inspect response in debugger
        breakpoint()  # <-- VS Code pauses here; inspect `response.content`

        if response.stop_reason == "end_turn":
            return response.content[0].text

        # Process tool calls
        tool_use = next((b for b in response.content if b.type == "tool_use"), None)
        if tool_use is None:
            break

        # Simulate tool execution
        tool_result = {"temperature": 22, "condition": "sunny"}

        messages += [
            {"role": "assistant", "content": response.content},
            {
                "role": "user",
                "content": [
                    {
                        "type": "tool_result",
                        "tool_use_id": tool_use.id,
                        "content": json.dumps(tool_result),
                    }
                ],
            },
        ]

    return "Max steps reached"

if __name__ == "__main__":
    result = asyncio.run(run_agent("What is the weather in Berlin?"))
    print(result)

import random

DEBUG_SAMPLE_RATE = 0.01  # log full payloads for 1% of runs in production

def should_log_full_payload(run_id: str) -> bool:
    # Deterministic per run_id so replay and live match
    return int(run_id.replace("-", ""), 16) % 10000 < int(DEBUG_SAMPLE_RATE * 10000)

import logging

class LazyJson:
    """Defer JSON serialization until the log record is actually emitted."""
    def __init__(self, obj):
        self._obj = obj
        self._cached = None

    def __str__(self):
        if self._cached is None:
            import json
            self._cached = json.dumps(self._obj, default=str)
        return self._cached

